  ["tips.flee.target"] = "Fuite de la cible\n|cffffffffAvec cette commande, la cible commence à fuir.|r\n\n|cffff0000Clic gauche pour exécuter la fuite de la cible|r\n|cff999999(Ordre d'exécution : Cible)|r\n\n|cffff0000Clic droit pour définir comme action par défaut|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.format.master"] = "Contrôle de formation\n|cffffffffCe contrôle vous permet de changer la formation de vos Bots.\nL'ordre d'exécution montre les destinataires des commandes.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour demander la formation actuelle|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.format.arrow"] = "Formation en flèche\n|cffffffffLes Bots se rangent en formation de flèche.\nLeur ligne de vue est dans votre direction.\n\n1ère ligne : Tanks\n2ème ligne : Combattants au corps à corps\n3ème ligne : Combattants à distance\n4ème ligne : Soigneurs|r\n\n|cffff0000Clic gauche pour sélectionner la formation en flèche|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.format.queue"] = "Formation en file\n|cffffffffLes Bots se rangent en formation défensive.\nLeur ligne de vue est dans votre direction.|r\n\n|cffff0000Clic gauche pour sélectionner la formation en file|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.format.near"] = "Formation rapprochée\n|cffffffffLes Bots se rangent près de vous.\nLeur ligne de vue est dans votre direction.|r\n\n|cffff0000Clic gauche pour sélectionner la formation rapprochée|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.format.melee"] = "Formation de mêlée\n|cffffffffLes Bots se rangent pour les combats au corps à corps.\nLeur ligne de vue est dans votre direction.|r\n\n|cffff0000Clic gauche pour sélectionner la formation de mêlée|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.format.line"] = "Formation en ligne\n|cffffffffLes Bots se rangent à gauche et à droite en ligne parallèle.\nLeur ligne de vue est dans votre direction.|r\n\n|cffff0000Clic gauche pour sélectionner la formation en ligne|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.format.circle"] = "Formation en cercle\n|cffffffffLes Bots se rangent en cercle autour de vous.\nLeur ligne de vue est orientée vers l'extérieur.|r\n\n|cffff0000Clic gauche pour sélectionner la formation en cercle|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.format.chaos"] = "Formation en chaos\n|cffffffffChaque Bot vous suit individuellement.\nIls se placent partout où ils le souhaitent.\nLa ligne de vue peut être dans toutes les directions.|r\n\n|cffff0000Clic gauche pour sélectionner la formation en chaos|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.format.shield"] = "Formation de bouclier\n|cffffffffLes Bots se rangent devant, à gauche et à droite de vous.\nLeur ligne de vue est dans votre direction.|r\n\n|cffff0000Clic gauche pour sélectionner la formation de bouclier|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.beast.master"] = "Contrôle de BEAST MASTER\n|cffffffffCe contrôle est destiné au Module BEAST MASTER de Azerothcore.\nLe BEAST MASTER permet à chaque personnage d'avoir un animal de compagnie comme les chasseurs.\nVos personnages peuvent apprendre les sorts nécessaires auprès de White Fang.\nWhite Fang doit être placé dans le World par le GameMaster.\nL'ordre d'exécution montre le récepteur des commandes.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.beast.release"] = "Libérer la Bête\n|cffffffffCette commande libérera la bête.|r\n\n|cffff0000Clic gauche pour libérer la bête|r\n|cff999999(Ordre d'exécution : Cible, Raid, Groupe)|r",
  ["tips.beast.revive"] = "Réanimer la Bête\n|cffffffffCette commande réanimera la bête.|r\n\n|cffff0000Clic gauche pour réanimer la bête|r\n|cff999999(Ordre d'exécution : Cible, Raid, Groupe)|r",
  ["tips.beast.heal"] = "Soigner la Bête\n|cffffffffCette commande soignera la bête.|r\n\n|cffff0000Clic gauche pour soigner la bête|r\n|cff999999(Ordre d'exécution : Cible, Raid, Groupe)|r",
  ["tips.beast.feed"] = "Donner à manger à la Bête\n|cffffffffCette commande nourrira la bête.|r\n\n|cffff0000Clic gauche pour nourrir la bête|r\n|cff999999(Ordre d'exécution : Cible, Raid, Groupe)|r",
  ["tips.beast.call"] = "Appeler la Bête\n|cffffffffCette commande appellera la bête.|r\n\n|cffff0000Clic gauche pour appeler la bête|r\n|cff999999(Ordre d'exécution : Cible, Raid, Groupe)|r",
  ["tips.creator.master"] = "Contrôle du créateur\n|cffffffffCe contrôle vous permet de créer des Bots par classe.\nLa limite par défaut est de 40 Bots par compte.\nIl n'existe pas de commande pour les supprimer après utilisation.\nInvitez-les donc dans votre liste d'amis pour les réutiliser.\nL'ordre d'exécution montre les destinataires des commandes.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.warrior"] = "Créer-Guerrier\n|cffffffffCe bouton créera un bot Guerrier.|r\n\n|cffff0000Clic-Gauche pour choisir le sexe de votre Guerrier.|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.warlock"] = "Créer-Démoniste\n|cffffffffCe bouton créera un bot Démoniste.|r\n\n|cffff0000Clic-Gauche pour choisir le sexe de votre Démoniste.|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.shaman"] = "Créer-Chaman\n|cffffffffCe bouton créera un bot Chaman.|r\n\n|cffff0000Clic-Gauche pour choisir le sexe de votre Chaman.|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.rogue"] = "Créer-Voleur\n|cffffffffCe bouton créera un bot Voleur.|r\n\n|cffff0000Clic-Gauche pour choisir le sexe de votre Voleur.|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.priest"] = "Créer-Prêtre\n|cffffffffCe bouton créera un bot Prêtre.|r\n\n|cffff0000Clic-Gauche pour choisir le sexe de votre Prêtre.|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.paladin"] = "Créer-Paladin\n|cffffffffCe bouton créera un bot Paladin.|r\n\n|cffff0000Clic-Gauche pour choisir le sexe de votre Paladin|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.mage"] = "Créer-Mage\n|cffffffffCe bouton créera un bot Mage.|r\n\n|cffff0000Clic-Gauche pour choisir le sexe de votre Mage.|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.hunter"] = "Créer-Chasseur\n|cffffffffCe bouton créera un bot Chasseur.|r\n\n|cffff0000Clic-Gauche pour choisir le sexe de votre Chasseur.|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.druid"] = "Créer-Druide\n|cffffffffCe bouton créera un bot Druide.|r\n\n|cffff0000Clic-Gauche pour choisir le sexe de votre Druide.|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.deathknight"] = "Créer-Chevalier de la mort\n|cffffffffCe bouton créera un bot Chevalier de la mort.|r\n\n|cffff0000Clic-Gauche pour choisir le sexe de votre Chevalier de la mort.|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.notarget"] = "Je n'ai pas de cible.",
  ["tips.creator.gendermale"] = "Crée un compagnon masculin.\n|cffffffffFort, courageux, toujours prêt pour la bataille... ou une chope.|r\n\n|cffff0000Clic-Gauche pour créer|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.genderfemale"] = "Crée un compagnon féminin.\n|cffffffffGracieuse, redoutable, et à ne jamais sous-estimer.|r\n\n|cffff0000Clic-Gauche pour créer|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.genderrandom"] = "Crée un bot avec un sexe aléatoire.\n|cffffffffLes vents du destin en décideront !|r\n\n|cffff0000Clic-Gauche pour créer|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.creator.inspect"] = "Inspecter la cible\n|cffffffffCe bouton ouvrira la fenêtre d'inspection de votre cible.|r\n\n|cffff0000Clic gauche pour ouvrir la fenêtre d'inspection|r\n|cff999999(Ordre d'exécution : Cible)|r",
  ["tips.creator.init"] = "Initialisation automatique\n|cffffffffUtilisez ce bouton pour initialiser automatiquement votre cible, votre raid ou votre groupe.\nIl y a deux limitations, car l'équipement sera écrasé :\n- cela ne fonctionne pas les bots dans le roster de Playerbot.\n- cela ne fonctionne pas les bots dans le roster de Guilde.|r\n\n|cffff0000Clic gauche pour initialiser automatiquement votre cible|r\n|cff999999(Ordre d'exécution : Cible)|r\n\n|cffff0000Clic droit pour initialiser automatiquement votre groupe|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.unit.selfbot"] = "Selfbot\n|cffffffffCe bouton active ou désactive le mode Selfbot.|r\n\n|cffff0000Clic gauche pour exécuter le Selfbot|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.unit.button"] = "|cffffffff\nCe bouton ajoute ou supprime NAME de votre groupe.\nMultiBot demandera à Playerbot les stratégies de combat et hors-combat.\nLes stratégies peuvent être configurées avec les barres de boutons à gauche et à droite.\nLes barres de boutons apparaîtront après l'ajout du Bot.|r\n\n|cffff0000Clic gauche pour ajouter NAME|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour supprimer NAME|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.master"] = "Contrôle des unités\n|cffffffffDans ce contrôle, vous trouverez les Playerbots.\nChaque bouton représente un de vos personnages, membres de guilde ou amis.\nL'ordre d'exécution montre les destinataires des commandes.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les unités|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour actualiser la liste|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.filter"] = "Filtre de classe\n|cffffffffAvec le filtre de classe, vous pouvez filtrer les unités par classe.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour réinitialiser le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.deathknight"] = "Filtre de classe\n|cffffffffFiltre les chevaliers de la mort.|r\n\n|cffff0000Clic gauche pour filtrer les chevaliers de la mort|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.druid"] = "Filtre de classe\n|cffffffffFiltre les druides.|r\n\n|cffff0000Clic gauche pour filtrer les druides|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.hunter"] = "Filtre de classe\n|cffffffffFiltre les chasseurs.|r\n\n|cffff0000Clic gauche pour filtrer les chasseurs|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.mage"] = "Filtre de classe\n|cffffffffFiltre les mages.|r\n\n|cffff0000Clic gauche pour filtrer les mages|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.paladin"] = "Filtre de classe\n|cffffffffFiltre les paladins.|r\n\n|cffff0000Clic gauche pour filtrer les paladins|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.priest"] = "Filtre de classe\n|cffffffffFiltre les prêtres.|r\n\n|cffff0000Clic gauche pour filtrer les prêtres|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.rogue"] = "Filtre de classe\n|cffffffffFiltre les voleurs.|r\n\n|cffff0000Clic gauche pour filtrer les voleurs|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.shaman"] = "Filtre de classe\n|cffffffffFiltre les chamans.|r\n\n|cffff0000Clic gauche pour filtrer les chamans|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.warlock"] = "Filtre de classe\n|cffffffffFiltre les démonistes.|r\n\n|cffff0000Clic gauche pour filtrer les démonistes|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.warrior"] = "Filtre de classe\n|cffffffffFiltre les guerriers.|r\n\n|cffff0000Clic gauche pour filtrer les guerriers|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.none"] = "Filtre de classe\n|cffffffffSupprime le filtre de classe.|r\n\n|cffff0000Clic gauche pour supprimer le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.roster"] = "Filtre de Rôle\n|cffffffffAvec le Filtre de Rôle, vous pouvez basculer entre différents rôles.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cffff0000Clic droit bascule vers de Roster Actifs|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.actives"] = "Filtre de Rôle\n|cffffffffAffiche le rôle Actif.|r\n\n|cffff0000Clic gauche pour sélectionner le rôle Actif|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.players"] = "Filtre de Rôle\n|cffffffffAffiche le rôle des Bots Joueurs.\nNormalement, vos personnages et autres qui sont restés dans votre groupe.|r\n\n|cffff0000Clic gauche pour sélectionner le rôle des Bots Joueurs|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.members"] = "Filtre de Rôle\n|cffffffffAffiche le rôle de la Guilde.\nLe rôle de la Guilde n'affiche pas vos personnages.|r\n\n|cffff0000Clic gauche pour sélectionner le rôle de la Guilde|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.friends"] = "Filtre de Rôle\n|cffffffffAffiche le rôle des Amis.\nLe rôle des Amis n'affiche ni vos personnages ni les membres de la Guilde.|r\n\n|cffff0000Clic gauche pour sélectionner le rôle des Amis|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.favorites"] = "Filtre de Roster\n|cffffffffAfficher uniquement les Bots que vous avez marqués comme Favoris.|r\n\n|cffff0000Clic gauche pour activer|r\n|cff999999(Exécuté par : Système)|r",
  ["tips.units.pvpstatsmaster"] = "Statistiques JcJ\n|cffffffffEnvoyer la commande de statistiques JcJ à...|r\n\n|cffff0000Clic gauche pour ouvrir le menu|r\n|cff999999(Exécuté par : Système)|r",
  ["tips.units.pvpstatstobot"] = "Envoyer au bot",
  ["tips.units.pvpstatstoparty"] = "Envoyer au groupe",
  ["tips.units.pvpstatstoraid"] = "Envoyer au raid",
  ["tips.units.browse"] = "Parcourir\n|cffffffffAvec ce bouton, vous pouvez parcourir les Rôles.\nIl sera caché si le Rôle contient moins de 11 unités.|r\n\n|cffff0000Clic gauche pour parcourir le Rôle|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.invite"] = "Contrôle d'Invitation\n|cffffffffAvec ce Contrôle, vous pouvez remplir automatiquement votre groupe.\nLe bouton de gauche est pour 'Invitation au Groupe', les boutons de droite sont pour 'Invitation au Raid'.\nDe plus, un clic droit sur ce bouton ajoutera ou supprimera tous les Bots à la fois.\nCela signifie que, si vous n'êtes pas dans un groupe, tous les Bots seront ajoutés, sinon ils seront supprimés.|r\n\n|cffff0000Clic gauche pour afficher ou masquer le Contrôle|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour ajouter ou supprimer tous les Bots|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.inviteParty5"] = "Partie de Cinq\n|cffffffffAvec ce bouton, vous pouvez remplir votre Partie.\nCette fonctionnalité prend les unités du Rôle sélectionné en ignorant le filtre de classe.\nElle s'arrête à la fin du Rôle ou jusqu'à ce que le groupe atteigne 5 membres.|r\n\n|cffff0000Clic gauche pour inviter des membres de la Partie|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.inviteRaid10"] = "Raid de Dix\n|cffffffffAvec ce bouton, vous pouvez remplir votre Raid.\nCette fonctionnalité prend les unités du Rôle sélectionné en ignorant le filtre de classe.\nElle s'arrête à la fin du Rôle ou jusqu'à ce que le groupe atteigne 10 membres.|r\n\n|cffff0000Clic gauche pour inviter des membres du Raid|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.inviteRaid25"] = "Raid de Vingt-Cinq\n|cffffffffAvec ce bouton, vous pouvez remplir votre Raid.\nCette fonctionnalité prend les unités du Rôle sélectionné en ignorant le filtre de classe.\nElle s'arrête à la fin du Rôle ou jusqu'à ce que le groupe atteigne 25 membres.|r\n\n|cffff0000Clic gauche pour inviter des membres du Raid|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.inviteRaid40"] = "Raid de Quarante\n|cffffffffAvec ce bouton, vous pouvez remplir votre Raid.\nCette fonctionnalité prend les unités du Rôle sélectionné en ignorant le filtre de classe.\nElle s'arrête à la fin du Rôle ou jusqu'à ce que le groupe atteigne 40 membres.|r\n\n|cffff0000Clic gauche pour inviter des membres du Raid|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.units.alliance"] = "Connexion/Déconnexion de tous les PlayerBots\n|cffffffffConnecte ou déconnecte tous les PlayerBots auxquels vous avez accès.\nCette fonction peut prendre du temps pour remplir les barres de boutons de chaque PlayerBot,\nen fonction du nombre total de PlayerBots.\n\n|cffff0000Clic gauche pour connecter tous les PlayerBots|r\n|cff999999(Exécuté par : Système)|r\n\n|cffff0000Clic droit pour déconnecter tous les PlayerBots|r\n|cff999999(Exécuté par : Système)|r",
