  ["tips.sliders.rstbutn"] = "Réinitialiser",
  ["tips.main.master"] = "Contrôle Principal\n|cffffffffDans ce contrôle, vous trouverez les Auto-Commuts et les Commandes de Réinitialisation.\nL'Ordre d'exécution montre le destinataire des commandes.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour faire glisser et déplacer MultiBot|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.options"] = "Options-Switch\n|cffffffffOuvre le panneau des paramètres MultiBot avec des curseurs pour les intervalles d’actions.\n(Stats / Talents / Invitation / Tri) et la limitation du chat (Messages par seconde / Rafale).\nLes paramètres sont enregistrés par personnage.|r\n\n|cffff0000Clic gauche pour ouvrir ou fermer le panneau d’options|r\n|cff999999(Ordre d’exécution : Interface)|r",
  ["tips.main.coords"] = "Réinitialiser les Coordonnées\n|cffffffffRéinitialiser les Coordonnées des Fonctions :\nMultiBar, Inventaire, Grimoire, Itemus, Iconos et Sélecteur de Récompense|r\n\n|cffff0000Clic gauche pour réinitialiser les Coordonnées|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.masters"] = "Switch Maitre du Jeu\n|cffffffffCe switch activera ou désactivera le contrôle MJ.\nVous devez avoir les droits MJ pour activer le contrôle.|r\n\n|cffff0000Cliquez-gauche pour activer ou désactiver le contrôle MJ|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.rtsc"] = "Interrupteur RTSC\n|cffffffffCet interrupteur permet d'activer ou de désactiver le contrôle RTSC.|r\n\n|cffff0000Clic gauche pour activer ou désactiver le contrôle RTSC|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.raidus"] = "Raidus-Switch\n|cffffffffCe bouton ouvrira ou fermera le compositeur de raid.|r\n\n|cffff0000Clic gauche pour ouvrir ou fermer le compositeur de raid|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.creator"] = "Switch Créateur\n|cffffffffCe switch activera ou désactivera le mode créateur de Bot.|r\n\n|cffff0000Cliquez-gauche pour activer ou désactiver le mode créateur de Bot|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.beast"] = "Switch Maître des Bêtes\n|cffffffffCe switch activera ou désactivera le contrôle Maître des Bêtes.\nLe contrôle Maître des Bêtes gère le Module Maître des Bêtes d'Azerothcore.\nLe Module Maître des Bêtes permet à chaque personnage d'avoir un familier comme les chasseurs.\nVos personnages peuvent apprendre les sorts nécessaires auprès de White Fang.\nWhite Fang doit être placé dans le monde par l'Admin.|r\n\n|cffff0000Cliquez-gauche pour activer ou désactiver le contrôle Maître des Bêtes|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.expand"] = "Contrôle Rester-Suivre\n|cffffffffCe bouton développera ou réduira la fonction Rester-Suivre.\n|cffff0000Clic gauche pour développer ou réduire le Contrôle Rester-Suivre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.release"] = "Auto-Réanimation\n|cffffffffCette fonctionnalité détecte la mort des Bots.\nLes Bots morts sont automatiquement réanimés et invoqués.\nCela va ressusciter les bots en quelques secondes.|r\n\n|cffff0000Clic gauche pour activer ou désactiver l'Auto-Réanimation|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.stats"] = "Auto-Statistiques\n|cffffffffCette fonctionnalité visualise les valeurs de la commande Stat.\nLes valeurs des statistiques sont mises à jour toutes les 45 secondes.|r\n\n|cffff0000Clic gauche pour activer ou désactiver les Auto-Statistiques|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.reward"] = "Sélecteur de Récompense\n|cffffffffCette fonctionnalité visualise la sélection des récompenses.\nMon conseil est de sélectionner la récompense pour votre personnage en premier.\nEnsuite, vous n'aurez pas de problèmes en utilisant les boutons d'inspection.|r\n\nImportant :\nUne fois que votre personnage a terminé la quête, les bots doivent également terminer la quête.\nDonc ne fermez pas le Sélecteur de Récompense après que votre personnage ait reçu sa récompense.\n\n|cffffffffConfiguration Mod-Playerbot :\n- (doit) AiPlayerbot.AutoPickReward = no\n- (recommandé) AiPlayerbot.SyncQuestWithPlayer = 1|r\n\n|cffff0000Clic gauche pour activer ou désactiver le Sélecteur de Récompense|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour ouvrir le Sélecteur de Récompense|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.main.reset"] = "Réinitialiser les Bots\n|cffffffffCe bouton réinitialisera l'intelligence artificielle de vos Bots.|r\n\n|cffff0000Clic gauche pour réinitialiser l'intelligence artificielle|r\n|cff999999(Ordre d'exécution : Cible, Raid, Groupe)|r",
  ["tips.main.action"] = "Réinitialiser l'Action\n|cffffffffCe bouton réinitialisera l'action actuelle de vos Bots.|r\n\n|cffff0000Clic gauche pour réinitialiser l'Action|r\n|cff999999(Ordre d'exécution : Cible, Raid, Groupe)|r",
  ["tips.game.master"] = "Contrôle du Maître de Jeu\n|cffffffffDans ce contrôle, vous trouverez des commandes utiles pour le Maître de Jeu.\nL'Ordre d'exécution montre le destinataire des commandes.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour fermer MultiBot|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.game.necronet"] = "Réseau-Nécro\n|cffffffffCe bouton active ou désactive le Réseau-Nécro.\nSi le Réseau-Nécro est actif, vous trouverez des boutons de Cimetière sur la Carte du Monde.\nChaque bouton de Cimetière vous permet de vous téléporter au Cimetière correspondant.\nVous avez besoin de droits de Maître de Jeu pour utiliser ces boutons.|r\n\n|cffff0000Clic gauche pour activer ou désactiver le Réseau-Nécro|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.game.portal"] = "Portail de Mémoire\n|cffffffffDans cette boîte, vous trouverez les Gemmes de Mémoire.\nUtilisez les Gemmes de Mémoire pour stocker votre position actuelle.\nVous pouvez vous téléporter aux emplacements stockés en utilisant les Gemmes de Mémoire.\nL'Ordre d'exécution montre le destinataire des commandes.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les Gemmes de l'Âme|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.game.memory"] = "Gemme de Mémoire\n|cffffffffCette Gemme de Mémoire ABOUT.\nVous avez besoin de droits de Maître de Jeu pour utiliser ce bouton.|r\n\n|cffff0000Clic gauche pour stocker ou téléporter à l'emplacement|r\n|cff999999(Ordre d'exécution : Vous-même)|r\n\n|cffff0000Clic droit pour oublier l'emplacement|r\n|cff999999(Ordre d'exécution : Vous-même)|r",
  ["tips.game.itemus"] = "Itemus\n|cffffffffVous trouverez chaque objet dans la boîte du Maître de Jeu.\nIl vous suffit de cibler le joueur ou le bot, de cliquer à gauche sur l'objet et le souhait se réalise.\nImportant, tous les objets ne peuvent pas être générés, vous devrez donc essayer de découvrir.\nL'Ordre d'exécution montre le destinataire des commandes.|r\n\n|cffff0000Clic gauche pour ouvrir ou fermer l'Itemus|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.game.iconos"] = "Iconos\n|cffffffffVous trouverez chaque icône et son chemin dans cet outil.\nL'Ordre d'exécution montre le destinataire des commandes.|r\n\n|cffff0000Clic gauche pour ouvrir ou fermer l'Iconos|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.game.summon"] = "Invocation\n|cffffffffInvitez un joueur ou un bot ciblé à votre position.\nVous avez besoin de droits de Maître de Jeu pour utiliser ce bouton.|r\n\n|cffff0000Clic gauche pour invoquer votre cible|r\n|cff999999(Ordre d'exécution : Cible)|r",
  ["tips.game.appear"] = "Apparition\n|cffffffffVous apparaîtrez à la position du joueur ou du bot ciblé.\nVous avez besoin de droits de Maître de Jeu pour utiliser ce bouton.|r\n\n|cffff0000Clic gauche pour apparaître à votre cible|r\n|cff999999(Ordre d'exécution : Cible)|r",
  ["tips.game.delsvwarning"] = "|cffff4444ATTENTION|r : vous allez effacer TOUTES les saved variables de MultiBot.\nCette action est irréversible.\n\nSouhaitez-vous continuer ?",
  ["tips.game.delsv"] = "Supprimer les variables sauvegardées\n|cffffffffCe bouton effacera définitivement toutes les données du fichier MultiBot SavedVariables (MultiBot.lua).\nCette action est irréversible. Utilisez avec précaution !|r\n\n|cffff0000Clic gauche pour supprimer|r\n|cff999999(Exécuté au niveau système)|r",
  ["tips.quests.master"] = "Contrôle des Quêtes\n|cffffffffCe contrôle affiche la liste actuelle des quêtes.\nClic-Gauche sur les pages pour partager la quête avec vos bots.\nClic-Droit sur les pages pour abandonner votre quête et celle de vos bots.\nL'ordre d'exécution indique le destinataire des commandes.|r\n\n|cffff0000Clic-Gauche pour afficher ou cacher les options|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic-Droit pour rafraîchir les options|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.quests.accept"] = "Accepter Quêtes\n|cffffffffCe bouton ordonne aux bots de prendre toutes les quêtes du PNJ ciblé.\n\n|cffff0000Clic-Gauche pour tout accepter|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.quests.main"] = "Ouvrir le Menu Quêtes\n|cffffffffCe bouton ouvre le menu des quêtes.\n\n|cffff0000Clic-Gauche pour ouvrir|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.quests.talk"] = "Parler au PNJ\n|cffffffffCe bouton demande aux bots de parler au PNJ sélectionné pour prendre ou rendre une quête.\n\n|cffff0000Clic-Gauche pour ordonner|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.quests.talkerror"] = "Veuillez sélectionner un PNJ à qui parler.",
  ["tips.quests.questcomperror"] = "Veuillez cibler un bot pour interroger ses quêtes.",
  ["tips.quests.sendwhisp"] = "Demander au bot",
  ["tips.quests.sendpartyraid"] = "Demander au groupe ou raid.",
  ["tips.quests.completed"] = "Quêtes Terminées\n|cffffffffCe bouton vous permet de demander la liste des quêtes terminées à un bot ou à tous les bots.\n\n|cffff0000Clic-Gauche pour ouvrir le sous-menu|r\n|cff999999(Ordre d'exécution : Raid, Groupe, bot)|r",
  ["tips.quests.incompleted"] = "Quêtes Incomplètes\n|cffffffffCe bouton vous permet de demander la liste des quêtes non terminées à un bot ou à tous les bots.\n\n|cffff0000Clic-Gauche pour ouvrir le sous-menu|r\n|cff999999(Ordre d'exécution : Raid, Groupe, bot)|r",
  ["tips.quests.allcompleted"] = "Toutes les quêtes\n|cffffffffCe bouton vous permet de demander à un bot ou à tous les bots la liste de toutes les quêtes.\n\n|cffff0000Clic-Gauche pour ouvrir le sous-menu|r\n|cff999999(Ordre d'exécution : Raid, Groupe, bot)|r",
  ["tips.quests.incomplist"] = "Quêtes en cours du/des bot(s)",
  ["tips.quests.complist"] = "Liste des quêtes terminées du/des bot(s)",
  ["tips.quests.alllist"] = "Toutes les quêtes du/des bot(s)",
  ["tips.quests.compheader"] = "** Quêtes Terminées **",
  ["tips.quests.incompheader"] = "** Quêtes Incomplètes **",
  ["tips.quests.botsword"] = "Bots : ",
  ["tips.quests.gobsmaster"] = "Menu Objets du Jeu\n|cffffffffCe bouton ouvre le menu pour utiliser des objets du jeu.|r\n\n|cffff0000Clic-Gauche pour ouvrir|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.quests.gobenter"] = "Utiliser un Objet du Jeu\n|cffffffffCe bouton ouvre une fenêtre pour entrer le nom de l'objet du jeu.\n\n|cffff0000Clic-Gauche pour ouvrir la fenêtre|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.quests.gobsearch"] = "Rechercher un Objet du Jeu\n|cffffffffCe bouton ouvre une fenêtre listant les objets du jeu utilisables par les bots.\n\n|cffff0000Clic-Gauche pour ouvrir la fenêtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.quests.goberrorname"] = "Veuillez entrer un nom d'objet du jeu valide.",
  ["tips.quests.gobselectboterror"] = "Veuillez sélectionner le bot à qui envoyer la commande.",
  ["tips.quests.gobsnameerror"] = "Veuillez entrer un nom.",
  ["tips.quests.gobctrlctocopy"] = "CTRL + C pour copier",
  ["tips.quests.gobselectall"] = "Tout sélectionner",
  ["tips.quests.gobsfound"] = "Objets du Jeu trouvés",
  ["tips.quests.gobpromptname"] = "Nom de l'objet du jeu",
  ["tips.quests.gobnosearchdata"] = "Aucune donnée Capturée.",
  ["tips.group.group"] = "Sélecteur d’actions de groupe\n|cffffffffOuvre un sous-menu avec les actions de groupe suivantes :\nBoire, Libérer, Ranimer.|r\n\n|cffff0000Clic gauche pour développer.|r",
  ["tips.drink.group"] = "Boire en Groupe\n|cffffffffCe bouton ordonne au groupe de boire.\nL'Ordre d'exécution montre le destinataire des commandes.|r\n\n|cffff0000Clic gauche pour exécuter Boire en Groupe|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.release.group"] = "Libération de Groupe\n|cffffffffCe bouton permettra aux Bots morts de libérer leurs fantômes vers le prochain cimetière.\nL'Ordre d'exécution montre le destinataire des commandes.|r\n\n|cffff0000Clic gauche pour exécuter Libération de Groupe|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.revive.group"] = "Ressuscitation de Groupe\n|cffffffffCe bouton permettra aux Bots fantômes de ressusciter au prochain cimetière.\nL'Ordre d'exécution montre le destinataire des commandes.|r\n\n|cffff0000Clic gauche pour exécuter Ressuscitation de Groupe|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.summon.group"] = "Invocation de Groupe\n|cffffffffCe bouton invoque le groupe à votre position.\nL'Ordre d'exécution montre le destinataire des commandes.|r\n\n|cffff0000Clic gauche pour exécuter Invocation de Groupe|r\n|cff999999(Ordre d'exécution : Raid, Groupe)|r",
  ["tips.allbots.sellallvendor"] = "Vendre tous les objets gris vendables (TOUS LES BOTS)|cffffffff\nTous vos bots (ceux listés dans le panneau des unités) vendront tous les objets\nqui peuvent être vendus en toute sécurité au vendeur que vous ciblez actuellement.\nLes objets protégés (clés, Pierre de foyer, etc.) ne sont jamais vendus.|r\n\n|cffff0000Affecte chaque bot listé dans le panneau des unités.|r\n|cff999999(Exécuté par : chaque Bot)|r",
  ["tips.allbots.commandsallbots"] = "Vous permet d’envoyer des commandes à tous les Bots|cffffffff\nTous vos bots (ceux listés dans le panneau des unités) exécuteront la commande\n\n|cffff0000Affecte chaque bot listé dans le panneau des unités.|r\n|cff999999(Exécuté par : chaque Bot)|r",
  ["tips.allbots.maintenanceallbots"] = "Maintenance (TOUS LES BOTS)|cffffffff\nTous vos bots (ceux listés dans le panneau des unités) exécuteront la commande 'maintenance'.\nUtilisez ceci lorsque vous souhaitez que chaque bot effectue sa routine complète de maintenance en même temps.|r\n\n|cffff0000Affecte chaque bot listé dans le panneau des unités.|r\n|cff999999(Exécuté par : chaque Bot)|r",
  ["tips.inventory.sell"] = "Vendre des Objets|cffffffff\nActive le mode de vente de l'inventaire.\nVous devez cibler un marchand.\nPour des raisons de sécurité, votre Bot ne vendra pas :\n- chaque objet avec 'Clé' dans son nom\n- la Pierre de Retour|r\n\n|cffff0000Clic gauche pour vendre un objet|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.inventory.sellgrey"] = "Vendre tout le gris|cffffffff\nLe Bot vend tous les objets de qualité médiocre (gris) au marchand ciblé.\nAssurez-vous de cibler un marchand et que le Bot est à portée.|r\n\n|cffff0000N'affecte que le Bot dont l'inventaire est ouvert.|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.inventory.sellvendor"] = "Vendre tout ce qui est vendable|cffffffff\nLe Bot vend tous les objets vendables à ce marchand.\nLes objets protégés (Clés, Pierre de foyer, etc.) ne seront jamais vendus.|r\n\n|cffff0000N'affecte que le Bot dont l'inventaire est ouvert.|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.inventory.equip"] = "Équiper des Objets|cffffffff\nActive le mode d'équipement de l'inventaire.|r\n\n|cffff0000Clic gauche pour équiper un objet|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.inventory.use"] = "Utiliser des Objets|cffffffff\nActive le mode d'utilisation de l'inventaire.|r\n\n|cffff0000Clic gauche pour utiliser un objet|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.inventory.trade"] = "Échanger-Objets|cffffffff\nActive le mode Échange de l'inventaire.\nLa fenêtre d'inspection doit être fermée manuellement.\nIl n'existe aucune commande LUA pour cela.|r\n\n|cffff0000Clic gauche pour échanger un objet|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.inventory.drop"] = "Jeter des Objets|cffffffff\nActive le mode de jet de l'inventaire.\nPour des raisons de sécurité, votre Bot ne jettera pas :\n- chaque objet de qualité Épique ou supérieure\n- chaque objet avec 'Clé' dans son nom\n- la Pierre de Retour|r\n\n|cffff0000Clic gauche pour jeter un objet|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.inventory.open"] = "Ouvrir-Objets|cffffffff\nCe bouton ouvrira chaque sac de butin trouvable en premier dans votre inventaire.\nLe contenu sera automatiquement placé dans l'inventaire.|r\n\n|cffff0000Clic gauche pour ouvrir un sac de butin|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.itemus.level.master"] = "Filtre de Niveau|cffffffff\nFiltre les objets par niveau dans une plage de 10.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.level.L10"] = "Niveau 0 à 10|cffffffff\nAffiche les objets avec un niveau requis entre 0 et 10.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.level.L20"] = "Niveau 11 à 20|cffffffff\nAffiche les objets avec un niveau requis entre 11 et 20.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.level.L30"] = "Niveau 21 à 30|cffffffff\nAffiche les objets avec un niveau requis entre 21 et 30.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.level.L40"] = "Niveau 31 à 40|cffffffff\nAffiche les objets avec un niveau requis entre 31 et 40.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.level.L50"] = "Niveau 41 à 50|cffffffff\nAffiche les objets avec un niveau requis entre 41 et 50.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.level.L60"] = "Niveau 51 à 60|cffffffff\nAffiche les objets avec un niveau requis entre 51 et 60.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.level.L70"] = "Niveau 61 à 70|cffffffff\nAffiche les objets avec un niveau requis entre 61 et 70.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.level.L80"] = "Niveau 71 à 80|cffffffff\nAffiche les objets avec un niveau requis entre 71 et 80.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.rare.master"] = "Filtre de Qualité|cffffffff\nFiltre les objets par qualité.\nCe filtre est additionnel au filtre de niveau.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.rare.R00"] = "Qualité Mauvaise|cffffffff\nAffiche les objets de qualité mauvaise.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.rare.R01"] = "Qualité Commune|cffffffff\nAffiche les objets de qualité commune.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.rare.R02"] = "Qualité Non-Commune|cffffffff\nAffiche les objets de qualité non-commune.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.rare.R03"] = "Qualité Rare|cffffffff\nAffiche les objets de qualité rare.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.rare.R04"] = "Qualité Épique|cffffffff\nAffiche les objets de qualité épique.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.rare.R05"] = "Qualité Légendaire|cffffffff\nAffiche les objets de qualité légendaire.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.rare.R06"] = "Qualité Artefact|cffffffff\nAffiche les objets de qualité artefact.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.rare.R07"] = "Qualité Héritage|cffffffff\nAffiche les objets de qualité héritage.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.master"] = "Filtre d'Emplacement|cffffffff\nFiltre les objets par emplacement.\nCe filtre est additionnel aux filtres de niveau et de qualité.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S00"] = "Non-Equipable|cffffffff\nAffiche les objets qui ne sont pas équipables.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S01"] = "Emplacement de Tête|cffffffff\nAffiche les objets pour l'emplacement de tête.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S02"] = "Emplacement de Cou|cffffffff\nAffiche les objets pour l'emplacement de cou.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S03"] = "Emplacement d'Épaule|cffffffff\nAffiche les objets pour l'emplacement d'épaule.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S04"] = "Emplacement de Chemise|cffffffff\nAffiche les objets pour l'emplacement de chemise.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S05"] = "Emplacement de Torse|cffffffff\nAffiche les objets pour l'emplacement de torse.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S06"] = "Emplacement de Taille|cffffffff\nAffiche les objets pour l'emplacement de taille.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S07"] = "Emplacement de Jambes|cffffffff\nAffiche les objets pour l'emplacement de jambes.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S08"] = "Emplacement de Pieds|cffffffff\nAffiche les objets pour l'emplacement de pieds.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S09"] = "Emplacement de Poignets|cffffffff\nAffiche les objets pour l'emplacement de poignets.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S10"] = "Emplacement de Mains|cffffffff\nAffiche les objets pour l'emplacement de mains.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S11"] = "Emplacement de Doigt|cffffffff\nAffiche les objets pour l'emplacement de doigt.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S12"] = "Emplacement de Bijou|cffffffff\nAffiche les objets pour l'emplacement de bijou.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S13"] = "Emplacement d'Arme à une Main|cffffffff\nAffiche les objets pour l'emplacement d'arme à une main.\nRemarque : cet objet peut être utilisé comme armes principales et secondaires.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S14"] = "Emplacement de Bouclier|cffffffff\nAffiche les objets pour l'emplacement de bouclier.\nRemarque : cet emplacement est le même que pour les armes secondaires.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S15"] = "Emplacement à Distance|cffffffff\nAffiche les objets pour l'emplacement à distance.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S16"] = "Emplacement de Dos|cffffffff\nAffiche les objets pour l'emplacement de dos.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S17"] = "Emplacement d'Arme à Deux Mains|cffffffff\nAffiche les objets pour l'emplacement d'arme à deux mains.\nRemarque : cet emplacement est le même que pour les armes principales.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S18"] = "Emplacement de Sac|cffffffff\nAffiche les objets pour l'emplacement de sac.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S19"] = "Emplacement de Tabard|cffffffff\nAffiche les objets pour l'emplacement de tabard.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S20"] = "Emplacement de Robe|cffffffff\nAffiche les objets pour l'emplacement de robe.\nRemarque : cet emplacement est le même que pour les torses.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S21"] = "Emplacement d'Armes de Main Principale|cffffffff\nAffiche les objets pour l'emplacement d'armes de main principale.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S22"] = "Emplacement d'Armes de Main Secondaire|cffffffff\nAffiche les objets pour l'emplacement d'armes de main secondaire.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S23"] = "Emplacement d'Objets de Main Secondaire|cffffffff\nAffiche les objets pour l'emplacement d'objets de main secondaire.\nRemarque : cet emplacement est le même que pour les armes secondaires.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S24"] = "Emplacement de Munition|cffffffff\nAffiche les objets pour l'emplacement de munition.\nRemarque : cet emplacement est le même que pour les objets à distance.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S25"] = "Emplacement de Lancer|cffffffff\nAffiche les objets pour l'emplacement de lancer.\nRemarque : cet emplacement est le même que pour les objets à distance.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S26"] = "Emplacement à Distance Droite|cffffffff\nAffiche les objets pour l'emplacement à distance droite.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S27"] = "Emplacement de Carquois|cffffffff\nAffiche les objets pour l'emplacement de carquois.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.slot.S28"] = "Emplacement de Relique|cffffffff\nAffiche les objets pour l'emplacement de relique.|r\n\n|cffff0000Clic gauche pour définir le filtre|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.itemus.type"] = "Filtre de Type|cffffffff\nAvec ce filtre, vous pouvez basculer entre les objets du personnage joueur et les objets des personnages non-joueurs.\nCe filtre est additionnel aux filtres de niveau, de qualité et d'emplacement.|r\n\n|cffff0000Clic gauche pour activer ou désactiver les objets NPC|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.deathknight.presence.master"] = "Contrôle de Spécialisation|cffffffff\nCe contrôle vous permet de sélectionner, d'activer ou de désactiver la Spécialisation par défaut.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour activer ou désactiver la Spécialisation par défaut.|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.deathknight.presence.unholy"] = "Spécialisation Impie|cffffffff\nElle active la Spécialisation Impie.|r\n\n|cffff0000Clic gauche pour activer la Spécialisation Impie|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.deathknight.presence.frost"] = "Spécialisation Givre|cffffffff\nElle active la Spécialisation Givre.|r\n\n|cffff0000Clic gauche pour activer la Spécialisation Givre|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.deathknight.presence.blood"] = "Spécialisation Sang|cffffffff\nElle active la Spécialisation Sang.|r\n\n|cffff0000Clic gauche pour activer la Spécialisation Sang|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.deathknight.dps.master"] = "Contrôle DPS|cffffffff\nDans le contrôle DPS, vous trouverez les stratégies DPS générales.|r\n\n|cffff0000Clic gauche pour afficher ou masquer le contrôle DPS|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.deathknight.dps.dpsAssist"] = "Assistance DPS|cffffffff\nElle active les stratégies d'assistance DPS.\nDPS-AOE, Assistance DPS et Assistance Tank sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver l'Assistance DPS|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.deathknight.dps.dpsAoe"] = "DPS-AOE|cffffffff\nElle active les stratégies DPS-AOE.\nDPS-AOE, Assistance DPS et Assistance Tank sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver DPS-AOE|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.deathknight.dps.frostAoe"] = "AOE-GIVRE|cffffffff\nActive la stratégie AOE Givre.\nAOE-Givre, DPS-Assist et Tank-Assist sont mutuellement exclusives.\nUne seule de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver AOE-Givre|r\n|cf9999999(Ordre d’exécution : Bot)|r",
  ["tips.deathknight.dps.unholyAoe"] = "AOE-IMPIE|cffffffff\nActive la stratégie AOE Impie.\nAOE-Impie, DPS-Assist et Tank-Assist sont mutuellement exclusives.\nUne seule de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver AOE-Impie|r\n|cf9999999(Ordre d’exécution : Bot)|r",
  ["tips.deathknight.tankAssist"] = "Assistance Tank|cffffffff\nElle active les stratégies d'assistance Tank.\nDPS-AOE, Assistance DPS et Assistance Tank sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver l'Assistance Tank|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.heal"] = "Soins|cffffffff\nCela fait du Druide le guérisseur du groupe.\nBear, Félin, Caster et Heal sont mutuellement exclusifs.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver Soins|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.buff"] = "Buff|cffffffff\nCela permet au Druide de renforcer le groupe.|r\n\n|cffff0000Clic gauche pour activer ou désactiver Buff|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.playbook.master"] = "Feuille de route|cffffffff\nDans la feuille de route, vous trouverez les stratégies typiques de la classe.|r\n\n|cffff0000Clic gauche pour afficher ou masquer la feuille de route|r\n|cff9999999(Ordre d'exécution : Système)|r",
  ["tips.druid.playbook.casterDebuff"] = "Dégâts de Sort|cffffffff\nPermet au Lanceur d'utiliser des sorts de débuff pendant le combat.|r\n\n|cffff0000Clic gauche pour activer ou désactiver Dégâts de Sort|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.playbook.casterAoe"] = "AOE de Lanceur|cffffffff\nPermet au Lanceur d'utiliser des sorts AOE pendant le combat.|r\n\n|cffff0000Clic gauche pour activer ou désactiver AOE de Lanceur|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.playbook.caster"] = "Lanceur|cffffffff\nLe Lanceur devient un combattant à distance.\nOurs, Félin, Caster et Heal sont mutuellement exclusifs.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver Lanceur|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.playbook.catAoe"] = "AOE de Félin|cffffffff\nPermet au Félin d'utiliser des attaques AOE pendant le combat.|r\n\n|cffff0000Clic gauche pour activer ou désactiver AOE de Félin|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.playbook.cat"] = "Félin|cffffffff\nLe Félin devient un combattant de mêlée.\nOurs, Félin, Caster et Heal sont mutuellement exclusifs.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver Félin|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.playbook.bear"] = "Ours|cffffffff\nL'Ours correspond à un tank.\nOurs, Félin, Caster et Heal sont mutuellement exclusifs.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver Ours|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.playbook.melee"] = "Mêlée|cffffffff\nActive la stratégie Mêlée.\nSe place au corps-à-corps et privilégie les attaques physiques.\nIncompatible avec Lanceur de sorts et Soin.|r\n\n|cffff0000Clic gauche pour activer/désactiver Mêlée|r\n|cff999999(Ordre d’exécution : Bot)|r",
  ["tips.druid.dps.healerdps"] = "Soigneur-DPS|cffffffff\nActive la stratégie hybride Soigneur-DPS.\nInflige des dégâts par défaut et soigne si nécessaire.\nIncompatible avec Soin et OffHeal.|r\n\n|cffff0000Clic gauche pour activer/désactiver Soigneur-DPS|r\n|cff999999(Ordre d’exécution : Bot)|r",
  ["tips.druid.dps.master"] = "Contrôle DPS|cffffffff\nDans le contrôle DPS, vous trouverez les stratégies DPS générales.|r\n\n|cffff0000Clic gauche pour afficher ou masquer le contrôle DPS|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.dps.dpsAssist"] = "Assistance DPS|cffffffff\nCeci active les stratégies d'assistance DPS.\nDPS-AOE, Assistance DPS et Assistance Tank sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver l'Assistance DPS|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.dps.dpsDebuff"] = "DPS-Débuff|cffffffff\nCeci active les stratégies de débuff.\nLe Druide ne peut débuff qu'en tant que Lanceur.\nOurs, Félin, Caster et Heal sont mutuellement exclusifs.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver DPS-Débuff|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.dps.dpsAoe"] = "DPS-AOE|cffffffff\nCeci active les stratégies DPS-AOE.\nLe Druide ne peut utiliser AOE qu'en tant que Chat ou Lanceur.\nDPS-AOE, Assistance DPS et Assistance Tank sont mutuellement exclusives.\nOurs, Félin, Caster et Heal sont mutuellement exclusifs.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver DPS-AOE|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.dps.dps"] = "DPS|cffffffff\nCeci active les stratégies DPS.\nLe Druide ne peut utiliser les stratégies DPS qu'en tant que Chat.\nOurs, Félin, Caster et Heal sont mutuellement exclusifs.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver DPS|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.dps.offheal"] = "OffHeal|cffffffff\nDésactive le mode DPS et active le mode OffHeal,\nLes bots se concentreront sur les dégâts mais soigneront si nécessaire.\nUniquement pour les druides farouches.|r\n\n|cffff0000Clic gauche pour activer ou désactiver OffHeal|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.tankAssist"] = "Assistance Tank|cffffffff\nCeci active les stratégies d'assistance Tank.\nDPS-AOE, Assistance DPS et Assistance Tank sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver l'Assistance Tank|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.druid.tank"] = "Tank|cffffffff\nCeci active les stratégies de Tank.\nLe Druide ne peut tank qu'en tant qu'Ours.\nBear, Félin, Caster et Heal sont mutuellement exclusifs.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver Tank|r\n|cff9999999(Ordre d'exécution : Bot)|r",
  ["tips.hunter.pet.master"] = "Commandes du familier|cffffffff\nOuvre une barre avec plusieurs options d’invocation de familiers.|r\n\n|cffff0000Clic gauche pour afficher les options|r\n|cff999999(Ordre d’exécution : Système)|r",
  ["tips.hunter.pet.name"] = "Invoquer un familier par |cff00ff00son nom|r\n|cffffffffOuvre une liste des familiers disponibles, cliquez sur un nom pour l’invoquer.|r\n\n|cffff0000Clic gauche pour ouvrir la liste|r\n|cff999999(Ordre d’exécution : Bot)|r",
  ["tips.hunter.pet.id"] = "Invoquer un familier par |cff00ff00ID BDD|r\n|cffffffffUtilisez l’ID base de données d’une créature pour l’invoquer directement.|r\n\n|cffff0000Clic gauche pour entrer une ID|r\n|cff999999(Ordre d’exécution : Bot)|r",
  ["tips.hunter.pet.family"] = "Invoquer un familier aléatoire par |cff00ff00FAMILLE|r\n|cffffffffChoisissez une famille pour invoquer un familier aléatoire de ce type.|r\n\n|cffff0000Clic gauche pour sélectionner une famille|r\n|cff999999(Ordre d’exécution : Bot)|r",
  ["tips.hunter.pet.rename"] = "Renommer votre familier actuel\n|cffffffffOuvre une fenêtre pour définir un nouveau nom pour votre familier actif.|r\n\n|cffff0000Clic gauche pour renommer|r\n|cff999999(Ordre d’exécution : Bot)|r",
  ["tips.hunter.pet.abandon"] = "Renvoi du familier\n|cffffffffAvec cette commande vous pouvez renvoyer votre familier.|r\n\n|cffff0000Clic gauche pour renvoyer|r\n|cff999999(Ordre d’exécution : Bot)|r",
  ["tips.hunter.ownbutton"] = "Chasseur : %s\n|cffffffffCe bouton ouvre le menu du familier du chasseur.|r\n\n|cffff0000Clic gauche pour ouvrir/fermer|r\n|cffff0000Clic droit pour déplacer|r\n|cff999999(Ordre d’exécution : Système)|r",
  ["tips.hunter.pet.stances"] = "Comportements du familier\n|cffffffffOuvre le menu des comportements du familier.|r\n\n|cffff0000Clic gauche pour ouvrir/fermer|r\n|cff999999(Ordre d’exécution : Système)|r",
