  ["tips.mage.playbook.master"] = "Playbook|cffffffff\nDans le Playbook, vous trouverez les stratégies typiques de la classe.|r\n\n|cffff0000Clic gauche pour afficher ou masquer le Playbook|r\n|cff999999(Ordre d'exécution : Système)|r",
  ["tips.mage.playbook.arcaneAoe"] = "Arcane-AOE|cffffffff\nPermet au Mage d'utiliser des sorts AOE Arcane pendant le combat.|r\n\n|cffff0000Clic gauche pour activer ou désactiver Arcane-AOE|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.mage.playbook.arcane"] = "Magie Arcane|cffffffff\nPermet au Mage d'utiliser de la magie arcane pendant le combat.\nLa magie Arcane, de Givre et de Feu sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver la magie Arcane|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.mage.playbook.frostAoe"] = "Givre-AOE|cffffffff\nPermet au Mage d'utiliser des sorts AOE Givre pendant le combat.|r\n\n|cffff0000Clic gauche pour activer ou désactiver Givre-AOE|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.mage.playbook.frost"] = "Magie de Givre|cffffffff\nPermet au Mage d'utiliser de la magie Givre pendant le combat.\nLa magie Arcane, de Givre et de Feu sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver la magie de Givre|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.mage.playbook.fireAoe"] = "Feu-AOE|cffffffff\nPermet au Mage d'utiliser des sorts AOE de Feu pendant le combat.|r\n\n|cffff0000Clic gauche pour activer ou désactiver Feu-AOE|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.mage.playbook.fire"] = "Magie de Feu|cffffffff\nPermet au Mage d'utiliser de la magie de feu pendant le combat.\nLa magie Arcane, de Givre et de Feu sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver la magie de feu|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.mage.playbook.frostfireAoe"] = "GivreFeu AOE|cffffffff\nActive les stratégies de combat GivreFeu + AOE.\nDPS-AOE, DPS-Assist et Tank-Assist sont mutuellement exclusifs.\nUn seul de ces modes peut être actif.|r\n\n|cffff0000Clic-Gauche pour activer ou désactiver Frostfire AOE|r\n|cf9999999(Ordre d’exécution : Bot)|r",
  ["tips.mage.playbook.frostfire"] = "GivreFeu|cffffffff\nActive la stratégie de combat GivreFeu mono-cible.\nArcane, Givre, Feu et GivreFeu sont mutuellement exclusifs.\nUne seule spécialisation peut être active.|r\n\n|cffff0000Clic-Gauche pour activer ou désactiver Frostfire|r\n|cf9999999(Ordre d’exécution : Bot)|r",
  ["tips.mage.playbook.firestarter"] = "Firestarter|cffffffff\nActive la tactique \"Firestarter\" pour le gameplay Feu (ouverture/incantations instantanées).\nPeut être combiné avec votre spécialisation et l’option AOE.|r\n\n|cffff0000Clic-Gauche pour activer ou désactiver Firestarter|r\n|cf9999999(Ordre d’exécution : Bot)|r",
  ["tips.mage.dps.master"] = "Contrôle DPS|cffffffff\nDans le contrôle DPS, vous trouverez les stratégies DPS générales.|r\n\n|cffff0000Clic gauche pour afficher ou masquer le contrôle DPS|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.mage.dps.dpsAssist"] = "Assistance DPS|cffffffff\nCeci active les stratégies d'assistance DPS.\nDPS-AOE, Assistance DPS et Assistance Tank sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver l'Assistance DPS|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.mage.dps.dpsAoe"] = "DPS-AOE|cffffffff\nCeci active les stratégies DPS-AOE.\nDPS-AOE, Assistance DPS et Assistance Tank sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver DPS-AOE|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.mage.tankAssist"] = "Assistance Tank|cffffffff\nCeci active les stratégies d'assistance Tank.\nDPS-AOE, Assistance DPS et Assistance Tank sont mutuellement exclusives.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver l'Assistance Tank|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.paladin.heal"] = "Soins|cffffffff\nPermet au Paladin d'utiliser des sorts de soins.\nTank, DPS et Soins sont mutuellement exclusifs.\nSeule l'une de ces stratégies peut être activée.|r\n\n|cffff0000Clic gauche pour activer ou désactiver les soins|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.paladin.seal.master"] = "Contrôle de Bénédiction|cffffffff\nCe contrôle vous permet de sélectionner, activer ou désactiver la bénédiction par défaut.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour activer ou désactiver la bénédiction par défaut.|r\n|cff999999(Ordre d'exécution : Bot)|r",
