  ["tips.paladin.seal.bdps"] = "Bénédiction DPS|cffffffff\nActive la bénédiction DPS.|r\n\n|cffff0000Clic gauche pour activer la bénédiction DPS|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.paladin.naura.master"] = "Aura Non-Combat|cffffffff\nCe contrôle vous permet de sélectionner, activer ou désactiver l'aura non-combat par défaut.|r\n\n|cffff0000Clic gauche pour afficher ou masquer les options|r\n|cff999999(Ordre d'exécution : Système)|r\n\n|cffff0000Clic droit pour activer ou désactiver l'aura par défaut.|r\n|cff999999(Ordre d'exécution : Bot)|r",
