  ["tips.paladin.naura.barmor"] = "Aura d'Armure|cffffffff\nActive l'aura d'armure en tant qu'aura non-combat.|r\n\n|cffff0000Clic gauche pour activer l'aura d'armure|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.paladin.naura.bcast"] = "Aura de Concentration|cffffffff\nActive l'Aura de Concentration en tant qu'Aura Hors Combat.|r\n\n|cffff0000Clic gauche pour activer l'Aura d'Armure|r\n|cff999999(Ordre d'exécution : Bot)|r",
