  ["tips.paladin.caura.rfrost"] = "Aura de Résistance au Givre|cffffffff\nActive l'aura de résistance au Givre en tant qu'aura de combat.|r\n\n|cffff0000Clic gauche pour activer l'aura de résistance au Givre|r\n|cff999999(Ordre d'exécution : Bot)|r",
  ["tips.paladin.caura.rshadow"] = "Aura de Résistance à l'Ombre|cffffffff\nActive l'aura de résistance à l'ombre en tant qu'aura de combat.|r\n\n|cffff0000Clic gauche pour activer l'aura de résistance à l'ombre|r\n|cff999999(Ordre d'exécution : Bot)|r",
